div.script:
(function(){
    function initDropdowns(){
        var dds = document.querySelectorAll('.dir-dd');
        dds.forEach(function(dd){
            var trigger = dd.querySelector('.dir-dd-trigger');
            var panel   = dd.querySelector('.dir-dd-panel');
            var label   = dd.querySelector('.dir-dd-label');
            var native  = document.getElementById(dd.dataset.target);
            // Init label from native selected value
            if(native){
                var sel = native.options[native.selectedIndex];
                if(sel && sel.value) label.textContent = sel.text;
            }
            // Toggle open
            trigger.addEventListener('click', function(e){
                e.stopPropagation();
                var isOpen = dd.classList.contains('open');
                document.querySelectorAll('.dir-dd.open').forEach(function(x){ x.classList.remove('open'); });
                if(!isOpen) dd.classList.add('open');
            });
            trigger.addEventListener('keydown', function(e){
                if(e.key===' '||e.key==='Enter'){ e.preventDefault(); trigger.click(); }
                if(e.key==='Escape') dd.classList.remove('open');
            });
            // Option click
            panel.addEventListener('click', function(e){
                var opt = e.target.closest('.dir-dd-option');
                if(!opt) return;
                // Update selected class
                panel.querySelectorAll('.dir-dd-option').forEach(function(o){ o.classList.remove('selected'); });
                opt.classList.add('selected');
                // Update label
                label.textContent = opt.textContent.trim();
                // Sync native select
                if(native){
                    for(var i=0;i<native.options.length;i++){
                        if(String(native.options[i].value)===String(opt.dataset.value)){
                            native.selectedIndex=i; break;
                        }
                    }
                }
                dd.classList.remove('open');
            });
        });
        // Close on outside click
        document.addEventListener('click', function(){
            document.querySelectorAll('.dir-dd.open').forEach(function(x){ x.classList.remove('open'); });
        });
    }
    if(document.readyState==='loading'){
        document.addEventListener('DOMContentLoaded', initDropdowns);
    } else {
        initDropdowns();
    }
})();
